import{c as a,Q as i,j as l,m as s}from"./chunks/framework.CBiVa4O3.js";const b=JSON.parse('{"title":"Vercel / Netlify / Firebase / Supabase 免费套餐怎么看","description":"","frontmatter":{},"headers":[],"relativePath":"../cloudBasicsLearning/41-VercelNetlifyFirebaseSupabase免费套餐怎么看.md","filePath":"../cloudBasicsLearning/41-VercelNetlifyFirebaseSupabase免费套餐怎么看.md","lastUpdated":1779015580000}'),t={name:"../cloudBasicsLearning/41-VercelNetlifyFirebaseSupabase免费套餐怎么看.md"};function n(r,e,p,o,u,c){return i(),l("div",null,[...e[0]||(e[0]=[s(`<h1 id="vercel-netlify-firebase-supabase-免费套餐怎么看" tabindex="-1">Vercel / Netlify / Firebase / Supabase 免费套餐怎么看 <a class="header-anchor" href="#vercel-netlify-firebase-supabase-免费套餐怎么看" aria-label="Permalink to &quot;Vercel / Netlify / Firebase / Supabase 免费套餐怎么看&quot;">​</a></h1><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>Vercel、Netlify、Firebase、Supabase 的免费套餐,本质上是让小项目低门槛使用前端托管、Serverless、认证、数据库、存储和实时能力,但每个平台限制的维度完全不同。</p><p>它们最容易被混在一起比较成&quot;哪个更便宜&quot;。这其实问错了。Vercel 和 Netlify 更偏前端部署与边缘工作流,Firebase 和 Supabase 更偏后端能力与数据层。你要先判断自己需要的是&quot;把网站部署出去&quot;,还是&quot;给应用补一套后端基础设施&quot;。</p><hr><h2 id="放在系统哪里" tabindex="-1">放在系统哪里 <a class="header-anchor" href="#放在系统哪里" aria-label="Permalink to &quot;放在系统哪里&quot;">​</a></h2><p>这四类服务通常分别站在不同位置:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器</span></span>
<span class="line"><span>  -&gt; CDN / Frontend Hosting: Vercel / Netlify</span></span>
<span class="line"><span>  -&gt; Serverless Functions / Edge Functions</span></span>
<span class="line"><span>  -&gt; Backend Services: Firebase / Supabase</span></span>
<span class="line"><span>  -&gt; Database / Auth / Storage / Realtime</span></span></code></pre></div><p>Vercel 常见位置:</p><ul><li>Next.js 和现代前端应用部署</li><li>静态页面、SSR、ISR、API Routes、Edge Functions</li><li>图片优化、预览部署、团队协作</li></ul><p>Netlify 常见位置:</p><ul><li>静态站和 Jamstack 应用部署</li><li>构建、表单、函数、边缘逻辑、预览环境</li><li>和 Git 工作流结合较紧</li></ul><p>Firebase 常见位置:</p><ul><li>Auth、Firestore / Realtime Database、Storage、Cloud Functions</li><li>移动端和 Web App 的后端服务</li><li>Google 生态里的分析、推送、托管和云函数</li></ul><p>Supabase 常见位置:</p><ul><li>Postgres 数据库、Auth、Storage、Realtime、Edge Functions</li><li>想用 SQL、关系模型和开源生态的小团队</li><li>快速搭建 SaaS 后端和管理后台</li></ul><hr><h2 id="常见套餐-使用限制" tabindex="-1">常见套餐/使用限制 <a class="header-anchor" href="#常见套餐-使用限制" aria-label="Permalink to &quot;常见套餐/使用限制&quot;">​</a></h2><h3 id="查看方法" tabindex="-1">查看方法 <a class="header-anchor" href="#查看方法" aria-label="Permalink to &quot;查看方法&quot;">​</a></h3><p>看这些平台的免费套餐时,不要只看首页写的 Free。建议按功能拆:</p><ol><li>先确认免费计划是否允许商业使用、团队使用和生产使用</li><li>看 Usage / Limits / Pricing / Fair use / Quotas 页面</li><li>分开查 Hosting、Functions、Database、Storage、Auth、Bandwidth、Build、Logs</li><li>查超额后行为:自动计费、暂停、限流、降级、只读,还是要求升级</li><li>查预览环境、团队成员、私有项目、审计日志这些协作功能是否受限</li><li>查数据导出、备份、区域选择、迁移和删除项目的限制</li><li>对核心功能做一次压测或小流量演练,看真实用量会落在哪些计费项上</li></ol><p>免费套餐不是一张总表,而是一堆功能额度的组合。对小团队来说,最重要的是找出&quot;最先撞到的那一项&quot;。</p><h3 id="常见限制维度" tabindex="-1">常见限制维度 <a class="header-anchor" href="#常见限制维度" aria-label="Permalink to &quot;常见限制维度&quot;">​</a></h3><p>Vercel 常见限制维度:</p><ul><li>构建次数和构建分钟</li><li>Serverless / Edge Functions 调用、运行时间、并发</li><li>带宽和数据传输</li><li>图片优化次数和缓存行为</li><li>ISR / SSR 带来的动态渲染成本</li><li>预览部署、团队成员、项目数量和协作功能</li><li>日志保留、分析、监控和安全能力</li></ul><p>Vercel 适合 Next.js、前端优先、重视预览部署和开发体验的团队。不适合把大量长任务、重计算、稳定后台队列和复杂数据库逻辑都塞进函数里。风险点是 SSR、图片优化和函数调用会在流量上涨时一起放大。</p><p>Netlify 常见限制维度:</p><ul><li>构建分钟和并发构建</li><li>带宽和请求量</li><li>Functions / Edge Functions 调用与运行限制</li><li>表单提交、Identity、Large Media 等附加功能</li><li>预览环境、团队协作和访问控制</li><li>日志、分析和支持等级</li></ul><p>Netlify 适合静态站、文档站、营销站、Jamstack 应用和 Git 驱动发布。不适合重后端、强实时、大量动态 API 或复杂状态服务。风险点是构建资源、带宽、表单/函数等附加功能容易被忽略。</p><p>Firebase 常见限制维度:</p><ul><li>Firestore / Realtime Database 读写次数、存储、索引</li><li>Auth 用户、登录方式和安全规则</li><li>Storage 容量、下载流量、对象操作</li><li>Cloud Functions 调用、运行时间、冷启动、区域</li><li>Hosting 带宽、部署和缓存</li><li>日志、监控、分析、项目配额</li></ul><p>Firebase 适合移动端、实时协作、快速验证产品、弱运维团队和 Google 生态项目。不适合复杂关系查询、强 SQL 需求、对云厂商绑定敏感的项目。风险点是 NoSQL 数据模型和安全规则一开始设计错,后面迁移成本很高;读写次数也可能因为页面结构不合理被放大。</p><p>Supabase 常见限制维度:</p><ul><li>Postgres 存储、CPU、内存、连接数</li><li>数据库备份、保留时间、恢复能力</li><li>Auth 用户、邮件发送、第三方登录</li><li>Storage 容量、下载流量、对象操作</li><li>Realtime 连接数、消息量、频道数量</li><li>Edge Functions 调用、运行时间和日志</li><li>项目暂停、休眠、区域和团队协作限制</li></ul><p>Supabase 适合想用 Postgres、SQL、关系数据、RLS 权限和开源生态的小团队。不适合完全不懂数据库设计却直接暴露复杂查询的项目,也不适合把免费数据库当成高并发生产集群。风险点是连接数、慢查询、RLS 规则、备份恢复和免费项目暂停策略。</p><hr><h2 id="小团队建议" tabindex="-1">小团队建议 <a class="header-anchor" href="#小团队建议" aria-label="Permalink to &quot;小团队建议&quot;">​</a></h2><p>选这些平台时,先按应用形态判断:</p><ul><li>纯静态站、文档、博客、营销页:优先看 Netlify、Cloudflare Pages、Vercel</li><li>Next.js 产品、需要预览部署和 SSR/ISR:优先看 Vercel,同时控制动态渲染</li><li>移动 App、实时数据、快速后端:可以看 Firebase</li><li>SaaS、管理后台、关系数据、SQL 查询:可以看 Supabase</li><li>前端部署和后端数据分开:Vercel / Netlify + Supabase / Firebase 是常见组合</li></ul><p>保守建议:</p><ul><li>能静态化就静态化,不要默认 SSR</li><li>能缓存就缓存,不要让所有请求打到函数和数据库</li><li>登录态页面和公开页面分开设计</li><li>数据库访问必须走权限规则和服务端校验</li><li>免费套餐上线前必须看超额行为</li><li>核心数据必须确认备份、导出和迁移路径</li><li>不要把测试环境、预览环境和生产环境混在一个数据库里</li></ul><p>一个简单判断:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>如果你最关心&quot;部署体验&quot;,看 Vercel / Netlify.</span></span>
<span class="line"><span>如果你最关心&quot;后端能力&quot;,看 Firebase / Supabase.</span></span>
<span class="line"><span>如果你最关心&quot;长期可迁移&quot;,优先选择标准协议、SQL、可导出数据和清晰边界.</span></span></code></pre></div><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>Vercel、Netlify、Firebase、Supabase 的免费套餐不能只比价格,要按 Hosting、Functions、Database、Storage、Auth、Build、Bandwidth、Logs 分开看,并提前确认适合场景、不适合场景、超额行为和迁移路径。</p>`,46)])])}const h=a(t,[["render",n]]);export{b as __pageData,h as default};
